{
	struct files_ref_store_write_options *opts = &refs->write_opts_lazy_loaded;

	if (opts->initialized)
		return opts;

	opts->log_all_ref_updates = LOG_REFS_UNSET;
	repo_config(refs->base.repo, files_ref_store_config, opts);

	opts->initialized = true;
	return opts;
}

